-- Create "auth_sessions" table
CREATE TABLE "auth_sessions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "session_id_hash" character varying NOT NULL,
  "csrf_token_hash" character varying NOT NULL,
  "user_id" bigint NOT NULL,
  "expires_at" timestamptz NOT NULL,
  "last_active_at" timestamptz NULL,
  "ip" character varying NOT NULL DEFAULT '',
  "user_agent" character varying NOT NULL DEFAULT '',
  "status" character varying NOT NULL DEFAULT 'active',
  PRIMARY KEY ("id")
);
-- Create index "authsession_expires_at" to table: "auth_sessions"
CREATE INDEX "authsession_expires_at" ON "auth_sessions" ("expires_at");
-- Create index "authsession_session_id_hash" to table: "auth_sessions"
CREATE UNIQUE INDEX "authsession_session_id_hash" ON "auth_sessions" ("session_id_hash");
-- Create index "authsession_user_id_status" to table: "auth_sessions"
CREATE INDEX "authsession_user_id_status" ON "auth_sessions" ("user_id", "status");
